/**
 * Type definitions for the DataTable component
 * Ensures type safety across the component and its usage
 */

/** Represents a generic data item with string keys and unknown values */
export interface DataItem {
  [key: string]: unknown;
}

/** Props interface for the DataTable component */
export interface DataTableProps<T extends DataItem = DataItem> {
  /** The API URL to fetch data from */
  apiUrl: string;
  /** Optional custom headers for the fetch request */
  headers?: Record<string, string>;
  /** Optional CSS class name for styling */
  className?: string;
  /** Optional page size for pagination (default: 10) */
  pageSize?: number;
  /** Optional callback when data is successfully loaded */
  onDataLoaded?: (data: T[]) => void;
  /** Optional callback when an error occurs */
  onError?: (error: Error) => void;
  /** Optional custom render function for table cells */
  renderCell?: (key: string, value: unknown, item: T) => React.ReactNode;
  /** Optional title for the table */
  title?: string;
}

/** State for tracking the fetch operation */
export interface FetchState {
  /** Whether data is currently being fetched */
  isLoading: boolean;
  /** Error object if fetch failed */
  error: Error | null;
}

/** State for the data table */
export interface TableState<T extends DataItem> {
  /** The fetched data items */
  data: T[];
  /** Current page number (for pagination) */
  currentPage: number;
}

/** Column definition for table headers */
export interface Column {
  /** The key in the data object */
  key: string;
  /** The display label for the column header */
  label: string;
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import {
  DataTableProps,
  DataItem,
  FetchState,
  TableState,
  Column,
} from './types';
import './DataTable.styles.css';

/**
 * DataTable Component
 *
 * A reusable, production-ready React component that fetches data from an API
 * and displays it in a styled HTML table with loading states, error handling,
 * and empty state management.
 *
 * Features:
 * - TypeScript support with generic types
 * - Loading state indicator
 * - Error handling with user-friendly messages
 * - Empty state display
 * - Pagination support
 * - Accessible table markup
 * - Responsive design
 *
 * @example
 * ```tsx
 * <DataTable apiUrl="https://jsonplaceholder.typicode.com/users" />
 * ```
 */
export function DataTable<T extends DataItem = DataItem>({
  apiUrl,
  headers = {},
  className = '',
  pageSize = 10,
  onDataLoaded,
  onError,
  renderCell,
  title,
}: DataTableProps<T>): React.ReactElement {
  // Fetch state - tracks loading and error status
  const [fetchState, setFetchState] = useState<FetchState>({
    isLoading: false,
    error: null,
  });

  // Table state - stores fetched data and pagination info
  const [tableState, setTableState] = useState<TableState<T>>({
    data: [],
    currentPage: 1,
  });

  /**
   * Function to fetch data from the API
   * Wrapped in useCallback to maintain stable reference
   */
  const fetchData = useCallback(async () => {
    // Set loading state and clear any previous errors
    setFetchState({ isLoading: true, error: null });

    try {
      // Create AbortController for request cancellation
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 30000); // 30s timeout

      // Make the fetch request
      const response = await fetch(apiUrl, {
        headers: {
          'Content-Type': 'application/json',
          ...headers,
        },
        signal: controller.signal,
      });

      // Clear the timeout since request completed
      clearTimeout(timeoutId);

      // Check if response is OK (status 200-299)
      if (!response.ok) {
        throw new Error(
          `HTTP Error: ${response.status} ${response.statusText}`
        );
      }

      // Parse JSON response
      const result = (await response.json()) as T[];

      // Validate that result is an array
      if (!Array.isArray(result)) {
        throw new Error('Invalid data format: Expected an array of items');
      }

      // Update table state with fetched data
      setTableState((prev) => ({ ...prev, data: result }));
      setFetchState({ isLoading: false, error: null });

      // Call success callback if provided
      if (onDataLoaded) {
        onDataLoaded(result);
      }
    } catch (err) {
      // Handle different error types
      const error =
        err instanceof Error ? err : new Error('An unknown error occurred');

      setFetchState({ isLoading: false, error });

      // Call error callback if provided
      if (onError) {
        onError(error);
      }
    }
  }, [apiUrl, headers, onDataLoaded, onError]);

  /**
   * Effect to trigger data fetch on mount or when apiUrl changes
   */
  useEffect(() => {
    fetchData();
  }, [fetchData]);

  /**
   * Memoized calculation of table columns based on data keys
   * Only recalculates when data changes
   */
  const columns = useMemo<Column[]>(() => {
    if (tableState.data.length === 0) return [];

    // Get all unique keys from the first item and filter out nested objects
    return Object.keys(tableState.data[0])
      .filter((key) => {
        const value = tableState.data[0][key];
        // Only include primitive types as columns (string, number, boolean)
        // Filter out objects and arrays for cleaner display
        const valueType = typeof value;
        return valueType === 'string' ||
               valueType === 'number' ||
               valueType === 'boolean';
      })
      .slice(0, 8) // Limit to 8 columns for readability
      .map((key) => ({
        key,
        label: formatColumnHeader(key),
      }));
  }, [tableState.data]);

  /**
   * Memoized pagination calculations
   */
  const pagination = useMemo(() => {
    const totalPages = Math.ceil(tableState.data.length / pageSize);
    const startIndex = (tableState.currentPage - 1) * pageSize;
    const endIndex = startIndex + pageSize;
    const paginatedData = tableState.data.slice(startIndex, endIndex);

    return { totalPages, paginatedData, startIndex, endIndex };
  }, [tableState.data, tableState.currentPage, pageSize]);

  /**
   * Format a column header from camelCase/snake_case to Title Case
   */
  function formatColumnHeader(key: string): string {
    // Replace underscores and camelCase with spaces
    const spaced = key
      .replace(/[_-]/g, ' ')
      .replace(/([A-Z])/g, ' $1');

    // Capitalize first letter of each word
    return spaced
      .split(' ')
      .map((word) => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
      .join(' ')
      .trim();
  }

  /**
   * Handle page navigation
   */
  const goToPage = (page: number) => {
    if (page >= 1 && page <= pagination.totalPages) {
      setTableState((prev) => ({ ...prev, currentPage: page }));
    }
  };

  /**
   * Render the loading state
   */
  const renderLoading = (): React.ReactElement => (
    <div className="datatable-loading" role="status" aria-live="polite">
      <div className="datatable-spinner" aria-hidden="true" />
      <p>Loading data...</p>
    </div>
  );

  /**
   * Render the error state
   */
  const renderError = (): React.ReactElement => (
    <div className="datatable-error" role="alert" aria-live="assertive">
      <div className="datatable-error-icon" aria-hidden="true">⚠️</div>
      <h3>Error Loading Data</h3>
      <p>{fetchState.error?.message || 'Failed to load data

