export function App() {
  return (
    <div className="app">
      <h1>DataTable Examples</h1>

      {/* Example 1: Users table */}
      <DataTable
        apiUrl="https://jsonplaceholder.typicode.com/users"
        title="Users"
        pageSize={5}
      />
    </div>
  );
}

// ============================================================
// EXAMPLE 2: With Event Callbacks
// ============================================================

export function AppWithCallbacks() {
  const [lastLoadedData, setLastLoadedData] = useState<unknown[]>([]);
  const [lastError, setLastError] = useState<Error | null>(null);

  return (
    <div className="app">
      <DataTable
        apiUrl="https://jsonplaceholder.typicode.com/posts"
        title="Blog Posts"
        pageSize={10}
        onDataLoaded={(data) => {
          console.log('Data loaded:', data);
          setLastLoadedData(data);
        }}
        onError={(error) => {
          console.error('Error:', error);
          setLastError(error);
        }}
      />

      {lastError && (
        <div className="error-log">
          <p>Last error: {lastError.message}</p>
        </div>
      )}
    </div>
  );
}

