/**
 * TypeScript type definitions for the API SDK
 * Mirror of Python SDK types for type safety
 */

// ============================================================================
// Common Types
// ============================================================================

export interface ApiResponse<T> {
  data: T;
  meta?: ResponseMeta;
}

export interface ResponseMeta {
  total?: number;
  page?: number;
  per_page?: number;
  total_pages?: number;
}

export interface PaginationParams {
  page?: number;
  per_page?: number;
  sort_by?: string;
  sort_order?: 'asc' | 'desc';
}

// ============================================================================
// Authentication Types
// ============================================================================

export interface AuthToken {
  access_token: string;
  refresh_token: string;
  token_type: string;
  expires_in: number;
  expires_at: number; // Unix timestamp
}

export interface LoginCredentials {
  username: string;
  password: string;
}

export interface TokenRefreshRequest {
  refresh_token: string;
}

// ============================================================================
// User Types
// ============================================================================

export interface User {
  id: string;
  username: string;
  email: string;
  full_name?: string;
  is_active: boolean;
  is_admin: boolean;
  created_at: string;
  updated_at: string;
  last_login?: string;
}

export interface UserCreate {
  username: string;
  email: string;
  password: string;
  full_name?: string;
  is_active?: boolean;
  is_admin?: boolean;
}

export interface UserUpdate {
  username?: string;
  email?: string;
  full_name?: string;
  is_active?: boolean;
  is_admin?: boolean;
}

export interface UserListResponse {
  users: User[];
  meta: ResponseMeta;
}

// ============================================================================
// Item Types
// ============================================================================

export interface Item {
  id: string;
  name: string;
  description?: string;
  status: ItemStatus;
  owner_id: string;
  metadata?: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

export type ItemStatus = 'active' | 'inactive' | 'archived' | 'pending';

export interface ItemCreate {
  name: string;
  description?: string;
  status?: ItemStatus;
  metadata?: Record<string, unknown>;
}

export interface ItemUpdate {
  name?: string;
  description?: string;
  status?: ItemStatus;
  metadata?: Record<string, unknown>;
}

export interface ItemListResponse {
  items: Item[];
  meta: ResponseMeta;
}

// ============================================================================
// Webhook Types
// ============================================================================

export interface Webhook {
  id: string;
  url: string;
  events: WebhookEvent[];
  secret?: string;
  is_active: boolean;
  created_at: string;
  updated_at: string;
  last_triggered?: string;
}

export type WebhookEvent = 
  | 'user.created'
  | 'user.updated'
  | 'user.deleted'
  | 'item.created'
  | 'item.updated'
  | 'item.deleted'
  | '*';

export interface WebhookCreate {
  url: string;
  events: WebhookEvent[];
  secret?: string;
  is_active?: boolean;
}

export interface WebhookUpdate {
  url?: string;
  events?: WebhookEvent[];
  secret?: string;
  is_active?: boolean;
}

export interface WebhookListResponse {
  webhooks: Webhook[];
  meta: ResponseMeta;
}

export interface WebhookDelivery {
  id: string;
  webhook_id: string;
  event: WebhookEvent;
  payload: Record<string, unknown>;
  status: 'pending' | 'delivered' | 'failed';
  response_status?: number;
  response_body?: string;
  attempted_at: string;
  delivered_at?: string;
}

// ============================================================================
// Error Types
// ============================================================================

export interface ApiErrorResponse {
  error: {
    code: string;
    message: string;
    details?: Record<string, unknown>;
  };
  status_code: number;
}

// ============================================================================
// Request Options
// ============================================================================

export interface RequestOptions {
  params?: Record<string, string | number | boolean | undefined>;
  headers?: Record<string, string>;
  timeout?: number;
}

export interface ClientConfig {
  baseURL: string;
  apiKey?: string;
  timeout?: number;
  retries?: number;
  retryDelay?: number;
}

/**
 * Custom error classes for the API SDK
 * Mirrors Python SDK error structure
 */

/**
 * Base error class for all SDK errors
 */
export class SdkError extends Error {
  constructor(
    message: string,
    public readonly code: string = 'SDK_ERROR',
    public readonly details?: Record<string, unknown>
  ) {
    super(message);
    this.name = 'SdkError';

    // Maintains proper stack trace for where error was thrown (only in V8)
    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, SdkError);
    }
  }

  /**
   * Serialize error to JSON
   */
  toJSON(): Record<string, unknown> {
    return {
      name: this.name,
      code: this.code,
      message: this.message,
      details: this.details,
      stack: this.stack,
    };
  }
}

/**
 * Authentication-related errors
 */
export class AuthError extends SdkError {
  constructor(
    message: string,
    public readonly statusCode: number = 401,
    details?: Record<string, unknown>
  ) {
    super(message, 'AUTH_ERROR', details);
    this.name = 'AuthError';

    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, AuthError);
    }
  }
}

/**
 * Token-specific errors
 */
export class TokenExpiredError extends AuthError {
  constructor(message = 'Token has expired') {
    super(message, 401, { token_expired: true });
    this.name = 'TokenExpiredError';

    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, TokenExpiredError);
    }
  }
}

/**
 * Refresh token errors
 */
export class RefreshTokenError extends AuthError {
  constructor(message = 'Refresh token is invalid or expired') {
    super(message, 401, { refresh_failed: true });
    this.name = 'RefreshTokenError';

    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, RefreshTokenError);
    }
  }
}

/**
 * HTTP request errors from API
 */
export class ApiRequestError extends SdkError {
  constructor(
    message: string,
    public readonly statusCode: number,
    public readonly response?: Record<string, unknown>
  ) {
    super(message, `HTTP_${statusCode}`, response);
    this.name = 'ApiRequestError';

    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, ApiRequestError);
    }
  }

  /**
   * Check if error is a client error (4xx)
   */
  isClientError(): boolean {
    return this.statusCode >= 400 && this.statusCode < 500;
  }

  /**
   * Check if error is a server error (5xx)
   */
  isServerError(): boolean {
    return this.statusCode >= 500 && this.statusCode < 600;
  }
}

/**
 * Validation errors from API (422)
 */
export class ValidationError extends ApiRequestError {
  public readonly fieldErrors: Record<string, string[]>;

  constructor(
    message: string = 'Validation failed',
    fieldErrors: Record<string, string[]> = {},
    response?: Record<string, unknown>
  ) {
    super(message, 422, response);
    this.name = 'ValidationError';
    this.fieldErrors = fieldErrors;

    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, ValidationError);
    }
  }
}

/**
 * Not found errors (404)
 */
export class NotFoundError extends ApiRequestError {
  constructor(
    message: string = 'Resource not found',
    public readonly resourceType?: string,
    public readonly resourceId?: string
  ) {
    super(message, 404, { resourceType, resourceId });
    this.name = 'NotFoundError';

    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, NotFoundError);
    }
  }
}

/**
 * Conflict errors (409)
 */
export class ConflictError extends ApiRequestError {
  constructor(
    message: string = 'Resource conflict',
    public readonly conflictingField?: string
  ) {
    super(message, 409, { conflictingField });
    this.name = 'ConflictError';

    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, ConflictError);
    }
  }
}

/**
 * Rate limit errors (429)
 */
export class RateLimitError extends ApiRequestError {
  public readonly retryAfter?: number;
  public readonly limit?: number;
  public readonly remaining?: number;
  public readonly resetTime?: number;

  constructor(
    message: string = 'Rate limit exceeded',
    headers?: Record<string, string>
  ) {
    super(message, 429);
    this.name = 'RateLimitError';

    if (headers) {
      this.retryAfter = headers['retry-after'] 
        ? parseInt(headers['retry-after'], 10) 
        : undefined;
      this.limit = headers['x-ratelimit-limit'] 
        ? parseInt(headers['x-ratelimit-limit'], 10) 
        : undefined;
      this.remaining = headers['x-ratelimit-remaining'] 
        ? parseInt(headers['x-ratelimit-remaining'], 10) 
        : undefined;
      this.resetTime = headers['x-ratelimit-reset'] 
        ? parseInt(headers['x-ratelimit-reset'], 10) 
        : undefined;
    }

    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, RateLimitError);
    }
  }
}

/**
 * Network errors
 */
export class NetworkError extends SdkError {
  constructor(
    message: string = 'Network request failed',
    public readonly originalError?: Error
  ) {
    super(message, 'NETWORK_ERROR', 
      originalError ? { original: originalError.message } : undefined
    );
    this.name = 'NetworkError';

    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, NetworkError);
    }
  }
}

/**
 * Timeout errors
 */
export class TimeoutError extends SdkError {
  constructor(
    message: string = 'Request timeout',
    public readonly timeout: number = 30000
  ) {
    super(message, 'TIMEOUT_ERROR', { timeout });
    this.name = 'TimeoutError';

    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, TimeoutError);
    }
  }
}

/**
 * Type guard functions to check error types
 */
export function isSdkError(error: unknown): error is SdkError {
  return error instanceof SdkError;
}

export function isAuthError(error: unknown): error is AuthError {
  return error instanceof AuthError;
}

export function isApiRequestError(error: unknown): error is ApiRequestError {
  return error instanceof ApiRequestError;
}

export function isValidationError(error: unknown): error is ValidationError {
  return error instanceof ValidationError;
}

export function isNotFoundError(error: unknown): error is NotFoundError {
  return error instanceof NotFoundError;
}

export function isRateLimitError(error: unknown): error is RateLimitError {
  return error instanceof RateLimitError;
}

/**
 * Abstract base class for API resources
 * Provides common CRUD operations and request handling
 */

import type { AxiosInstance, AxiosResponse } from 'axios';
import { 
  ApiRequestError, 
  ValidationError, 
  NotFoundError,
  ConflictError,
  RateLimitError,
  NetworkError,
  TimeoutError
} from '../errors';
import type { ApiResponse, PaginationParams, RequestOptions } from '../types';

/**
 * Abstract base resource class
 * All resource classes extend this for consistent API interaction
 */
export abstract class BaseResource {
  protected readonly client: AxiosInstance;
  protected readonly basePath: string;

  constructor(client: AxiosInstance, basePath: string) {
    this.client = client;
    this.basePath = basePath;
  }

  /**
   * Build full URL for resource endpoints
   */
  protected buildUrl(path: string = ''): string {
    return path.length > 0 
      ? `${this.basePath}/${path}` 
      : this.basePath;
  }

  /**
   * Handle HTTP errors and convert to SDK error types
   */
  protected handleError(error: unknown): never {
    // Check if it's an axios error
    if (typeof error === 'object' && error !== null && 'response' in error) {
      const axiosError = error as { 
        response?: { 
          status: number; 
          data?: Record<string, unknown>;
          headers?: Record<string, string>;
        };
        message?: string;
        code?: string;
      };

      const status = axiosError.response?.status;
      const data = axiosError.response?.data;
      const headers = axiosError.response?.headers;
      const message = data?.error?.message || axiosError.message || 'Unknown error';

      // Convert to appropriate error type
      switch (status) {
        case 400:
          throw new ApiRequestError(`Bad request: ${message}`, 400, data);
        case 401:
          throw new ApiRequestError(`Unauthorized: ${message}`, 401, data);
        case 403:
          throw new ApiRequestError(`Forbidden: ${message}`, 403, data);
        case 404:
          throw new NotFoundError(message, undefined, undefined);
        case 409:
          throw new ConflictError(message);
        case 422:
          throw new ValidationError(
            message,
            (data?.error?.details as Record<string, string[]>) || {},
            data
          );
        case 429:
          throw new RateLimitError(message, headers);
        case 500:
          throw new ApiRequestError(`Server error: ${message}`, 500, data);
        case 502:
          throw new ApiRequestError(`Bad gateway: ${message}`, 502, data);
        case 503:
          throw new ApiRequestError(`Service unavailable: ${message}`, 503, data);
        default:
          throw new ApiRequestError(
            message,
            status || 0,
            data
          );
      }
    }

    // Handle network/timeout errors
    if (typeof error === 'object' && error !== null) {
      const err = error as { code?: string; message?: string };

      if (err.code === 'ECONNABORTED' || err.code === 'ETIMEDOUT') {
        throw new TimeoutError(err.message || 'Request timed out');
      }

      if (err.code === 'ENOTFOUND' || err.code === 'ECONNREFUSED') {
        throw new NetworkError('Network connection failed', 
          error instanceof Error ? error : undefined
        );
      }
    }

    // Default: wrap in generic API error
    throw new ApiRequestError(
      error instanceof Error ? error.message : 'Unknown error',
      0
    );
  }

  /**
   * Make GET request
   */
  protected async get<T>(path: string = '', options?: RequestOptions): Promise<T> {
    try {
      const response: AxiosResponse<T> = await this.client.get(
        this.buildUrl(path),
        {
          params: options?.params,
          headers: options?.headers,
          timeout: options?.timeout,
        }
      );
      return response.data;
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Make POST request
   */
  protected async post<T>(
    path: string = '',
    data: Record<string, unknown>,
    options?: RequestOptions
  ): Promise<T> {
    try {
      const response: AxiosResponse<T> = await this.client.post(
        this.buildUrl(path),
        data,
        {
          params: options?.params,
          headers: options?.headers,
          timeout: options?.timeout,
        }
      );
      return response.data;
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Make PUT request
   */
  protected async put<T>(
    path: string,
    data: Record<string, unknown>,
    options?: RequestOptions
  ): Promise<T> {
    try {
      const response: AxiosResponse<T> = await this.client.put(
        this.buildUrl(path),
        data,
        {
          params: options?.params,
          headers: options?.headers,
          timeout: options?.timeout,
        }
      );
      return response.data;
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Make PATCH request
   */
  protected async patch<T>(
    path: string,
    data: Record<string, unknown>,
    options?: RequestOptions
  ): Promise<T> {
    try {
      const response: AxiosResponse<T> = await this.client.patch(
        this.buildUrl(path),
        data,
        {
          params: options?.params,
          headers: options?.headers,
          timeout: options?.timeout,
        }
      );
      return response.data;
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Make DELETE request
   */
  protected async delete<T>(path: string, options?: RequestOptions): Promise<T> {
    try {
      const response: AxiosResponse<T> = await this.client.delete(
        this.buildUrl(path),
        {
          params: options?.params,
          headers: options?.headers,
          timeout: options?.timeout,
        }
      );
      return response.data;
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Build pagination parameters for list requests
   */
  protected buildPaginationParams(
    params: PaginationParams = {}
  ): Record<string, string> {
    const query: Record<string, string> = {};

    if (params.page !== undefined) {
      query.page = String(params.page);
    }
    if (params.per_page !== undefined) {
      query.per_page = String(params.per_page);
    }
    if (params.sort_by) {
      query.sort_by = params.sort_by;
      if (params.sort_order) {
        query.sort_order = params.sort_order;
      }
    }

    return query;
  }
}

