/**
 * API Client
 * Main entry point for the SDK with authentication and request handling
 */

import axios, {
  AxiosInstance,
  AxiosRequestConfig,
  AxiosResponse,
  InternalAxiosRequestConfig,
} from 'axios';
import {
  AuthToken,
  LoginCredentials,
  TokenRefreshRequest,
  ClientConfig,
} from './types';
import {
  AuthError,
  TokenExpiredError,
  RefreshTokenError,
  NetworkError,
  TimeoutError,
} from './errors';

// Resource imports
import { Users } from './resources/users';
import { Items } from './resources/items';
import { Webhooks } from './resources/webhooks';

/**
 * API Client class
 * Handles authentication, request interceptors, and resource access
 */
export class ApiClient {
  private client: AxiosInstance;
  private token: AuthToken | null = null;
  private refreshPromise: Promise<AuthToken> | null = null;
  private isRefreshing = false;

  // Resource accessors
  public users: Users;
  public items: Items;
  public webhooks: Webhooks;

  // Configuration
  private config: Required<ClientConfig>;

  /**
   * Create a new API client instance
   * @param config - Client configuration options
   */
  constructor(config: ClientConfig) {
    this.config = {
      timeout: 30000,
      retries: 3,
      retryDelay: 1000,
      ...config,
    };

    // Initialize axios instance
    this.client = axios.create({
      baseURL: this.config.baseURL,
      timeout: this.config.timeout,
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
      },
    });

    // Setup interceptors
    this.setupRequestInterceptor();
    this.setupResponseInterceptor();

    // Initialize resources
    this.users = new Users(this.client as any);
    this.items = new Items(this.client as any);
    this.webhooks = new Webhooks(this.client as any);
  }

  /**
   * Setup request interceptor for authentication
   */
  private setupRequestInterceptor(): void {
    this.client.interceptors.request.use(
      async (config: InternalAxiosRequestConfig) => {
        // Add auth token if available
        if (this.token && !this.isTokenExpired()) {
          config.headers.Authorization = `Bearer ${this.token.access_token}`;
        }

        // Add API key if provided
        if (this.config.apiKey) {
          config.headers['X-API-Key'] = this.config.apiKey;
        }

        return config;
      },
      (error) => Promise.reject(error)
    );
  }

  /**
   * Setup response interceptor for token refresh and retries
   */
  private setupResponseInterceptor(): void {
    this.client.interceptors.response.use(
      (response) => response,
      async (error) => {
        const originalRequest = error.config as InternalAxiosRequestConfig & {
          _retry?: boolean;
          _retryCount?: number;
        };

        // Handle 401 - Token expired
        if (error.response?.status === 401 && !originalRequest._retry) {
          if (this.isRefreshing) {
            // Wait for current refresh to complete
            try {
              await this.refreshPromise;
              return this.client(originalRequest);
            } catch (refreshError) {
              return Promise.reject(refreshError);
            }
          }

          originalRequest._retry = true;
          this.isRefreshing = true;

          try {
            await this.refreshAccessToken();
            return this.client(originalRequest);
          } catch (refreshError) {
            // Refresh failed, clear auth
            this.token = null;
            throw new RefreshTokenError('Session expired. Please login again.');
          } finally {
            this.isRefreshing = false;
            this.refreshPromise = null;
          }
        }

        // Handle retries for 5xx errors
        if (
          error.response?.status >= 500 &&
          (!originalRequest._retryCount || originalRequest._retryCount < this.config.retries)
        ) {
          originalRequest._retryCount = (originalRequest._retryCount || 0) + 1;

          // Exponential backoff
          const delay = this.config.retryDelay * Math.pow(2, originalRequest._retryCount - 1);
          await new Promise((resolve) => setTimeout(resolve, delay));

          return this.client(originalRequest);
        }

        return Promise.reject(error);
      }
    );
  }

  /**
   * Check if current token is expired
   */
  private isTokenExpired(): boolean {
    if (!this.token) return true;
    // Add 60 second buffer before actual expiry
    return Date.now() >= (this.token.expires_at - 60) * 1000;
  }

  /**
   * Refresh the access token using refresh token
   */
  private async refreshAccessToken(): Promise<AuthToken> {
    if (!this.token?.refresh_token) {
      throw new RefreshTokenError('No refresh token available');
    }

    // Prevent duplicate refresh requests
    if (this.refreshPromise) {
      return this.refreshPromise;
    }

    this.refreshPromise = this.performTokenRefresh();
    return this.refreshPromise;
  }

  /**
   * Perform the actual token refresh request
   */
  private async performTokenRefresh(): Promise<AuthToken> {
    try {
      const response: AxiosResponse<AuthToken> = await axios.post(
        `${this.config.baseURL}/auth/refresh`,
        {
          refresh_token: this.token?.refresh_token,
        } as TokenRefreshRequest
      );

      this.token = {
        ...response.data,
        expires_at: Date.now() + response.data.expires_in * 1000,
      };

      return this.token;
    } catch (error) {
      throw new RefreshTokenError('Failed to refresh token');
    }
  }

